import scrapy
from scrapy.http import FormRequest

class AutenticadoSpider(scrapy.Spider):
    name = 'autenticado'
    start_urls = ['https://exemplo.com/dashboard']

    def start_requests(self):
        # Primeiro faz login
        yield FormRequest(
            url='https://exemplo.com/login',
            formdata={
                'username': 'usuario_demo',
                'password': 'senha_demo'
            },
            callback=self.after_login
        )

    def after_login(self, response):
        # Verifica se login foi bem-sucedido
        if "Login falhou" in response.text:
            self.logger.error("❌ Falha no login")
            return

        self.logger.info("✅ Login realizado com sucesso!")

        # Agora acessa páginas protegidas
        for url in self.start_urls:
            yield scrapy.Request(url, callback=self.parse_dashboard)

    def parse_dashboard(self, response):
        # Extrai dados do dashboard
        dados = {
            'usuario': response.css('span.user-name::text').get(),
            'ultimo_acesso': response.css('div.last-login::text').get(),
            'tarefas': response.css('ul.tasks li::text').getall()
        }

        yield dados

        # Segue para outras seções
        for link in response.css('nav a.section::attr(href)').getall():
            yield response.follow(link, self.parse_secao)

    def parse_secao(self, response):
        yield {
            'secao': response.url,
            'conteudo': response.css('main').get()[:500]
        }

